import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull", () => {
  it("should correctly chain multiple through streams", () => {
    const results: number[] = [];

    // Source that emits values 1, 2, 3 then ends
    let count = 0;
    const source = (end: any, cb: Function) => {
